const fs = require('fs');
const path = require('path');

const _ = require('lodash');
const glob = require('glob');
const concat = require('concat');
const sass = require('node-sass');

const rootPath = path.join(__dirname, '../..');

const srcPath = path.join(rootPath, 'src');

const assetsPath = path.join(srcPath, 'assets');
const sassPath = path.join(assetsPath, 'sass');

const themePath = path.join(sassPath, 'theme');
const tmpThemePath = path.join(sassPath, '_theme');

require('shelljs/global');


/**
 * bx-ui sass 빌드 플러그인
 */
class SassBuildPlugin{

    constructor({
        outputFileName = '',
        outputStyle = ''
    } = {}){

        this.outputFileName = outputFileName;
        // sass 빌드 스타일
        // https://github.com/sass/node-sass#outputstyle
        this.outputStyle = outputStyle;
    }
    apply(compiler){

        let self = this;

        compiler.plugin('done', function(){

            const outputFileName = self.outputFileName;
            const outputStyle = self.outputStyle;
            const outputPath = this.options.output.path;

            if (_.isEmpty(outputFileName)){
                throw new Error('Not found outputFileName property');
            }

            // 임시 테마 경로를 생성한다.
            if (!fs.existsSync(tmpThemePath)) mkdir('-p', tmpThemePath);

            /**********************************************************************
             * 테마 관련 css 파일을 생성한다.
             **********************************************************************/
            // 테마 sass 파일 빌드
            const sassThemeFilePaths = glob.sync(path.join(themePath, '**/*.scss'));

            // 오리지널 css 테마 파일 수
            let originalThemeFileLength = 0;

            _.forEach(sassThemeFilePaths, v => {

                const baseFileName = path.basename(v, '.scss');
                const cssFilePath = path.join(themePath, `_original/${`${baseFileName}.css`}`);

                if (fs.existsSync(cssFilePath)){
                    ++originalThemeFileLength;
                }
            });

            // 병합된 파일 수
            let fileCount = 0;

            _.forEach(sassThemeFilePaths, v => {

                const baseFileName = path.basename(v, '.scss');

                const cssFileName = `${baseFileName}.css`;
                const sassFileName = `${baseFileName}.scss`;

                const cssFilePath = path.join(themePath, `_original/${cssFileName}`);
                const sassFilePath = v;
                const tmpSassFilePath = path.join(tmpThemePath, sassFileName);

                if (fs.existsSync(cssFilePath)){

                    // 오리지널 css 파일과, sass 파일을 병합한다.
                    concat([cssFilePath, sassFilePath]).then(v => {

                        // 병합된 sass 파일을 생성한다.
                        fs.writeFileSync(tmpSassFilePath, v, 'utf-8');

                        // sass 빌드
                        const themeSourceData = sass.renderSync({
                            file: tmpSassFilePath,
                            outputStyle: outputStyle
                        });

                        // outputPath 에 theme 디렉토리를 생성한다.
                        mkdir('-p', path.join(outputPath, `assets/theme`));

                        // (병합)빌드된 css 파일을 생성한다.
                        fs.writeFileSync(path.join(outputPath, `assets/theme/${cssFileName}`), themeSourceData.css, 'utf-8');

                        // 임시 디렉토리를 삭제한다.
                        if (originalThemeFileLength === ++fileCount){

                            // tmp 테마 폴더를 생성한다.
                            rm('-rf', tmpThemePath);
                        }
                    });
                }
            });

            /**********************************************************************
             * 앱 css 파일을 생성한다.
             **********************************************************************/
            const outputFilePath = path.join(outputPath, `/assets/css/${outputFileName}`);
            const appSourceData = sass.renderSync({
                file: path.join(sassPath, 'app.scss'),
                outputStyle: self.outputStyle
            });

            // 디렉토리 생성
            mkdir('-p', path.join(outputPath, 'assets/css'));

            // 파일 생성
            fs.writeFileSync(outputFilePath, appSourceData.css, 'utf-8');
        });
    };
}

module.exports = SassBuildPlugin;